/// C: `static KOption getoption(Header *h, const char **fmt, int *size)`
fn getoption(h: &mut Header, fmt: &[u8], pos: &mut usize, size: &mut usize) -> Result<KOption, LuaError> {
    // C: struct cD { char c; union { LUAI_MAXALIGN; } u; };
